mapper.delete:
DELETE FROM ai_stu_portrait_unit
WHERE stu_id = #{stuId}
  AND classroom_id = #{classroomId}
  AND course_id = #{courseId}

mapper.select:
SELECT unit_id as id,
       unit_name as unitName,
       datavalue as dataValue,
       stu_datavalue as stuDataValue,
       `type`,
       order_num as orderNum,
       pid
FROM ai_stu_portrait_unit
WHERE stu_id = #{stuId}
  AND classroom_id = #{classroomId}
  AND course_id = #{courseId}
  AND num = #{num}
ORDER BY order_num
